#include <iostream>
#include <algorithm>
#include <math.h>
using namespace std;

int main()
{
    long long n,ans=1;
    cin>>n;
    long long temp=n;
    int sqrtn=sqrt(n);
    for(long i=2;i<=sqrtn;i++)
    {
        int count=0;
        while(!(temp%i))
        {
            count++;
            temp/=i;
        }

        if(count%2)
        {
            ans*=i;
        }
        if(temp==1)
        {
            break;
        }
    }
    ans*=temp;
    cout<<ans;
    return 0;
}
